"""三国志占い：六十干支（日柱）に三国志のキャラクターを割り当てる。

【割り当ての方針】
三国志の人物は、生年（年）すら不明な者も多く、日柱の算出に必要な
「年・月・日」までそろった正確な生年月日は、ほぼ誰も史料に残っていない
（巷で見かける誕生日の多くは旧暦かつ後世の創作で諸説ある）。
そのため本占いでは、各人物を **史実・性格・五行のイメージ** から
六十干支に割り当てている。日付レベルの生年月日が確実に分かる人物が
いれば、その干支へ差し替えられる構造にしてある。

index は shichu.py の干支インデックス(0=甲子 .. 59=癸亥)と対応する。
"""
from __future__ import annotations

from dataclasses import dataclass

# 勢力（陣営）と表示色
FACTION_COLOR = {
    "魏": "#1c5fb0",   # 青
    "蜀": "#2f9e44",   # 緑
    "呉": "#e8590c",   # 朱
    "群雄": "#7048e8",  # 紫（独立勢力・在野・その他）
}


@dataclass
class Character:
    index: int       # 干支index(0..59)
    name: str        # 名前
    yomi: str        # 読み
    faction: str     # 魏 / 蜀 / 呉 / 群雄
    title: str       # 肩書き・役割
    reason: str      # その干支に割り当てた理由
    history: str = ""  # 史実（実在の人物の生涯）

    @property
    def color(self) -> str:
        return FACTION_COLOR.get(self.faction, "#868e96")


